1.
```
#include <cstdlib>
#include <iostream>
using namespace std;

char encoder[26] = {'C','S','P',0};
char decoder[26];

string st;

int main()  {
  int k = 0;
  for (int i = 0; i < 26; ++i)
    if (encoder[i] != 0) ++k;
  for (char x ='A'; x <= 'Z'; ++x) {
    bool flag = true;
    for (int i = 0; i < 26; ++i)
      if (encoder[i] ==x) {
        flag = false;
        break;
      }
      if (flag) {
        encoder[k]= x;
        ++k;
      }
  }
  for (int i = 0; i < 26; ++i)
     decoder[encoder[i]- 'A'] = i + 'A';
  cin >> st;
  for (int i = 0; i < st.length( ); ++i)
    st[i] = decoder[st[i] -'A'];
  cout << st;
  return 0;
}
```

вҖўеҲӨж–ӯйўҳ

  1)  иҫ“е…Ҙзҡ„еӯ—з¬ҰдёІеә”еҪ“еҸӘз”ұеӨ§еҶҷеӯ—жҜҚз»„жҲҗпјҢеҗҰеҲҷеңЁи®ҝй—®ж•°з»„ж—¶еҸҜиғҪи¶Ҡз•ҢгҖӮпјҲ пјү  
  2)  иӢҘиҫ“е…Ҙзҡ„еӯ—з¬ҰдёІдёҚжҳҜз©әдёІпјҢеҲҷиҫ“е…Ҙзҡ„еӯ—з¬ҰдёІдёҺиҫ“еҮәзҡ„еӯ—з¬ҰдёІдёҖе®ҡдёҚдёҖж ·гҖӮпјҲпјү  
  3)  е°Ҷз¬¬ 12 иЎҢзҡ„ `i < 26` ж”№дёә `i < 16`пјҢзЁӢеәҸиҝҗиЎҢз»“жһңдёҚдјҡж”№еҸҳгҖӮпјҲ пјү  
  4)  е°Ҷз¬¬ 26 иЎҢзҡ„ `i < 26` ж”№дёә `i < 16`пјҢзЁӢеәҸиҝҗиЎҢз»“жһңдёҚдјҡж”№еҸҳгҖӮпјҲ пјү

вҖўеҚ•йҖүйўҳ

  5пјү иӢҘиҫ“еҮәзҡ„еӯ—з¬ҰдёІдёә $\texttt{ABCABCABCA}$пјҢеҲҷдёӢеҲ—иҜҙжі•жӯЈзЎ®зҡ„жҳҜпјҲ пјүгҖӮ



  6пјүиӢҘиҫ“еҮәзҡ„еӯ—з¬ҰдёІдёә $\texttt{CSPCSPCSPCSP}$пјҢеҲҷдёӢеҲ—иҜҙжі•жӯЈзЎ®зҡ„жҳҜпјҲ пјүгҖӮ

2.
```cpp
#include <iostream>
using namespace std;

long long n, ans;
int k, len;
long long d[1000000];

int main() {
  cin >> n >> k;
  d[0] = 0;
  len= 1;
  ans = 0;
  for (long long i = 0; i <n; ++i) {
    ++d[0];
    for (int j = 0; j + 1<len; ++j) {
      if (d[j] == k) {
        d[j] = 0;
        d[j + 1] += 1;
        ++ans;
      }
    }
    if (d[len- 1] == k) {
      d[len - 1] = 0;
      d[len] =1;
      ++len;
      ++ans;
    }
  }
  cout << ans << endl;
  return 0;
}
```

  еҒҮи®ҫиҫ“е…Ҙзҡ„ $n$ жҳҜдёҚи¶…иҝҮ $2^{62}$ зҡ„жӯЈж•ҙж•°пјҢ$k$ йғҪжҳҜдёҚи¶…иҝҮ $10000$ зҡ„жӯЈж•ҙж•°пјҢе®ҢжҲҗдёӢйқўзҡ„еҲӨж–ӯйўҳе’ҢеҚ•йҖүйўҳпјҡ

- еҲӨж–ӯйўҳ 

1) иӢҘ $k=1$пјҢеҲҷиҫ“еҮә $\mathrm{ans}$ ж—¶пјҢ$\mathrm{len}=n$гҖӮпјҲ пјү  
2) иӢҘ $k>1$пјҢеҲҷиҫ“еҮә $\mathrm{ans}$ ж—¶пјҢ$\mathrm{len}$ вҖ”е®ҡе°ҸдәҺ $n$гҖӮпјҲ  пјү  
3) иӢҘ $k>1$пјҢеҲҷиҫ“еҮә $\mathrm{ans}$ ж—¶пјҢ$k^{len}$ вҖ”е®ҡеӨ§дәҺ $n$гҖӮпјҲ  пјү

- еҚ•йҖүйўҳ

4) иӢҘиҫ“е…Ҙзҡ„ $n$ зӯүдәҺпјҡ$10^{15}$пјҢиҫ“е…Ҙзҡ„ $k$ дёә $1$пјҢеҲҷиҫ“еҮәзӯүдәҺпјҲ  пјүгҖӮ

5) иӢҘиҫ“е…Ҙзҡ„ $n$ зӯүдәҺ $205,891,132,094,649$пјҲеҚі $3^{30}$пјүпјҢиҫ“е…Ҙзҡ„ $k$ дёә $3$пјҢеҲҷиҫ“еҮәзӯүдәҺпјҲ пјүгҖӮ


6) иӢҘиҫ“е…Ҙзҡ„ $n$ зӯүдәҺ $100,010,002,000,090$пјҢиҫ“е…Ҙзҡ„ $k$ дёә $10$пјҢеҲҷиҫ“еҮәзӯүдәҺпјҲ пјүгҖӮ

3.
```cpp
#include <algorithm>
#include <iostream>
using namespace std;                     

int n;                                   
int d[50][2];                            
int ans;                                 

void dfs(int n, int sum) {               
  if (n == 1) {                            
    ans = max(sum, ans);           
    return;                                   
  }                                        
  for (int i = 1; i < n; ++i) {            
    int a = d[i - 1][0], b = d[i - 1][1];  
    int x = d[i][0], y = d[i][1];            
    d[i - 1][0] = a + x;                     
    d[i - 1][1] = b + y;                     
    for (int j = i; j < n - 1; ++j)            
      d[j][0] = d[j + 1][0], d[j][1] = d[j + 1][1];
    int s = a + x + abs(b - y);              
    dfs(n - 1, sum + s);                    
    for (int j = n - 1; j > i; --j)          
      d[j][0] = d[j - 1][0], d[j][1] = d[j - 1][1];
    d[i - 1][0] = a, d[i - 1][1] = b;        
    d[i][0] = x, d[i][1] = y;                
  }                                        
}                                        

int main() {                             
  cin >> n;                                
  for (int i = 0; i < n; ++i)              
  cin >> d[i][0];
  for (int i = 0; i < n;++i)
     cin >> d[i][1];
  ans = 0;
  dfs(n, 0);
  cout << ans << endl;
  return 0;
}
```

еҒҮи®ҫиҫ“е…Ҙзҡ„ $n$ жҳҜдёҚи¶…иҝҮ $50$ зҡ„жӯЈж•ҙж•°пјҢ`d[i][0]`гҖҒ`d[i][1]` йғҪжҳҜдёҚи¶…иҝҮ $10000$ зҡ„жӯЈж•ҙж•°пјҢе®ҢжҲҗдёӢйқўзҡ„еҲӨж–ӯйўҳе’ҢеҚ•йҖүйўҳпјҡ

- еҲӨж–ӯйўҳ 

  1) иӢҘиҫ“е…Ҙ $n$ дёә $0$пјҢжӯӨзЁӢеәҸеҸҜиғҪдјҡжӯ»еҫӘзҺҜжҲ–еҸ‘з”ҹиҝҗиЎҢй”ҷиҜҜгҖӮпјҲ пјү
  2) иӢҘиҫ“е…Ҙ $n$ дёә $20$пјҢжҺҘдёӢжқҘзҡ„иҫ“е…Ҙе…Ёдёә $0$пјҢеҲҷиҫ“еҮәдёә $0$гҖӮпјҲ пјү
  3) иҫ“еҮәзҡ„ж•°дёҖе®ҡдёҚе°ҸдәҺиҫ“е…Ҙзҡ„ `d[i][0]` е’Ң `d[i][1]` зҡ„д»»ж„ҸдёҖдёӘгҖӮпјҲ пјү

- еҚ•йҖүйўҳ

  4) иӢҘиҫ“е…Ҙзҡ„ $n$ дёә $20$пјҢжҺҘдёӢжқҘзҡ„иҫ“е…ҘжҳҜ $20$ дёӘ $9$ е’Ң $20$ дёӘ $0$пјҢеҲҷиҫ“еҮәдёәпјҲ пјүгҖӮ


  5) иӢҘиҫ“е…Ҙзҡ„ $n$ дёә $30$пјҢжҺҘдёӢжқҘзҡ„иҫ“е…ҘжҳҜ $30$ дёӘ $0$ е’Ң $30$ дёӘ $5$пјҢеҲҷиҫ“еҮәдёәпјҲ пјүгҖӮ


  6) пјҲ4 еҲҶпјүиӢҘиҫ“е…Ҙзҡ„ $n$ дёә $15$пјҢжҺҘдёӢжқҘзҡ„иҫ“е…ҘжҳҜ $15$ еҲ° $1$пјҢд»ҘеҸҠ  $15$ еҲ° $1$пјҢеҲҷиҫ“еҮәдёәпјҲ пјүгҖӮ

